import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { AppBar, Toolbar, Button, Typography, Box, useTheme } from '@mui/material';

const Navbar = () => {
  const theme = useTheme();
  const navigate = useNavigate();

  const navItemStyle = {
    textDecoration: 'none',
    color: 'white',
    flexGrow: 1,
    textAlign: 'left',
    padding: theme.spacing(1),
    '&:hover': {
      textDecoration: 'underline',
    },
  };

  return (
    <AppBar position="static" sx={{ backgroundColor: '#2D3748' /* Tailwind bg-gray-800 */, color: 'white' }}>
      <Toolbar>
        <Box sx={{ display: 'flex', flexGrow: 1 }}>
          <Typography variant="h6" noWrap sx={{ flexGrow: 1, textAlign: 'center' }}>
            <Link to="/" style={navItemStyle}>
              Home
            </Link>
          </Typography>
          <Link to="/dataset" style={navItemStyle}>
            Dataset
          </Link>
          <Link to="/bgp_llama" style={navItemStyle}>
            BGP-LLaMA
          </Link>
        </Box>
        <Button color="primary" variant="contained" onClick={() => navigate('https://huggingface.co/hyonbokan/BGPStream13-10k-cutoff-1024-max-2048')}>
          Download models
        </Button>
      </Toolbar>
    </AppBar>
  );
};

export default Navbar;
